insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('cecile', 'Dr Cécile Adjovi-Mensah', 'Pionnière', 'Santé', 'Ouémé', 'Médecin de santé publique — 38 ans de pratique en zones rurales', 'Médecin de santé publique. Trente-huit ans à servir les populations rurales de l''Ouémé. Spécialiste reconnue de la résilience des systèmes de soins en zones difficiles.', 38, 'Retraitée active', 'Mentorat ouvert', 2847, 100, null, '{"Santé","Recherche-action","Ouémé"}', '{"1988 — Premier réseau de relais communautaires de santé maternelle dans l''Ouémé, repris par le Ministère en 1995.","2007 — Protocole de soins itinérants pour zones inondables : −41 % de mortalité maternelle sur cinq ans.","2019 — Rapport « Résilience hospitalière en contexte de ressources contraintes » pour l''OMS."}', '{"mathias","norbert","auguste"}', 'Aux jeunes médecins qui me liront : la santé publique ne se résume pas aux statistiques nationales. Elle se joue au dispensaire de village, dans la confiance de la matrone, dans la patience qu''on met à expliquer plutôt qu''à prescrire. Faites-en autant et vous aurez votre histoire à raconter.', '{"Profil consulté":"2 847 fois","Capsules vues":"3 542","Téléchargements PDF":"128","Mentorés actifs":"7"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('mathias', 'Ing. Mathias Houénou', 'Pionnier', 'Ingénierie', 'Atacora', 'Hydraulicien — Réseaux d''eau pour 47 communes de la CEDEAO', 'Ingénieur hydraulicien. Quarante ans à concevoir des réseaux d''eau potable dans des territoires que personne ne voulait desservir.', 41, 'Retraité actif', 'Conseil ponctuel', 1934, 100, 'https://images.unsplash.com/photo-1736896165046-5df757614776?w=800&auto=format&fit=crop&q=70', '{"Ingénierie","Eau & assainissement","Atacora"}', '{"1998 — Réseau gravitaire de Natitingou desservant 22 000 habitants sans pompe, encore en service.","2012 — Méthode de captage en zone de socle cristallin, adoptée par trois pays."}', '{"cecile","justin","theophile"}', 'Un réseau d''eau n''est pas un ouvrage, c''est une promesse. Concevez toujours ce que la commune pourra entretenir seule dans vingt ans — pas ce qui impressionne au moment de l''inauguration.', '{"Profil consulté":"1 934 fois","Capsules vues":"1 208","Téléchargements PDF":"74","Mentorés actifs":"4"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('henriette', 'Maître Henriette Kpogan', 'Pionnière', 'Droit', 'Littoral', 'Magistrate — Présidente honoraire de la Cour d''Appel de Cotonou', 'Magistrate. Quarante-deux ans au service de la justice béninoise, dont vingt à former la relève.', 42, 'Honoraire', 'Mentorat ouvert', 2210, 100, 'https://images.unsplash.com/photo-1581475319737-4ae69b8926c7?q=80&w=800&auto=format&fit=crop', '{"Droit","OHADA","Littoral"}', '{"2010 — Refonte du module OHADA de l''École de la magistrature, encore enseigné.","2016 — Premier recueil commenté de jurisprudence commerciale béninoise."}', '{"emile","theophile","cecile"}', 'Le droit n''est pas un texte, c''est une pratique de la mesure. Aux jeunes magistrats : doutez de vos certitudes, écoutez la partie la plus faible deux fois plutôt qu''une, et n''oubliez jamais que derrière chaque dossier il y a une vie.', '{"Profil consulté":"2 210 fois","Capsules vues":"1 640","Téléchargements PDF":"97","Mentorés actifs":"6"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('solange', 'Mme Solange Tomèty', 'Pionnière', 'Agriculture', 'Borgou', 'Agronome — Adaptation variétale du maïs sahélien sur 35 ans', 'Agronome sélectionneuse. Trente-cinq ans à documenter et améliorer les variétés de maïs résistantes à la sécheresse.', 35, 'Retraitée active', 'Mentorat ouvert', 1502, 100, null, '{"Agriculture","Sélection variétale","Borgou"}', '{"1997 — Identification de la lignée « Sô-3 », tolérante à 45 jours de stress hydrique.","2014 — Réseau de 60 paysans-sélectionneurs formés à la conservation variétale."}', '{"anastasie","mathias","albertine"}', 'Une semence, c''est une bibliothèque vivante. Chaque variété qu''on laisse disparaître est un chapitre qu''aucune université ne pourra réécrire. Documentez, partagez, semez.', '{"Profil consulté":"1 502 fois","Capsules vues":"940","Téléchargements PDF":"61","Mentorés actifs":"5"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('emile', 'Pr Émile Sossou', 'Pionnier', 'Recherche', 'Atlantique', 'Économiste — Ancien directeur du Centre de recherche de l''UNB', 'Économiste. Quarante ans à observer les politiques monétaires de l''Afrique de l''Ouest.', 40, 'Professeur émérite', 'Conseil ponctuel', 1788, 100, 'https://images.unsplash.com/photo-1590697442615-a381b5b557c7?q=80&w=800&auto=format&fit=crop', '{"Recherche","Économie","Politique monétaire"}', '{"2001 — Premier modèle d''inflation calibré sur les données béninoises.","2015 — Étude fondatrice sur l''informalité et la transmission de la politique monétaire."}', '{"gisele","henriette","albertine"}', 'L''économie africaine ne se comprend pas avec des modèles importés. Observez d''abord, modélisez ensuite. Le marché de Dantokpa vous en apprendra plus qu''un manuel de Chicago.', '{"Profil consulté":"1 788 fois","Capsules vues":"1 102","Téléchargements PDF":"88","Mentorés actifs":"3"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('auguste', 'Pr Auguste Bossou', 'Pionnier', 'Éducation', 'Mono', 'Pédagogue — Fondateur de quatre lycées techniques au Bénin', 'Pédagogue et bâtisseur d''écoles. Trente-neuf ans à penser l''enseignement technique comme un levier de dignité.', 39, 'Retraité actif', 'Mentorat ouvert', 1361, 100, null, '{"Éducation","Enseignement technique","Mono"}', '{"2003 — Référentiel national des métiers du bâtiment, toujours en vigueur.","2018 — Quatrième lycée technique ouvert, plus de 3 000 diplômés au total."}', '{"cecile","solange","theophile"}', 'On a trop longtemps fait croire aux enfants que la main qui travaille valait moins que la main qui écrit. Je laisse à la relève une conviction simple : un bon soudeur est aussi précieux qu''un bon juriste.', '{"Profil consulté":"1 361 fois","Capsules vues":"780","Téléchargements PDF":"52","Mentorés actifs":"8"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('justin', 'Pr Justin Dégboé', 'Pionnier', 'Ingénierie', 'Plateau', 'Architecte — Plus de 200 édifices publics au Bénin et au Togo', 'Architecte de la commande publique. Quarante ans à dessiner des écoles, des marchés, des hôpitaux.', 40, 'Retraité actif', 'Conseil ponctuel', 1120, 55, 'https://images.unsplash.com/flagged/photo-1555497742-77cf45746c7f?q=80&w=800&auto=format&fit=crop', '{"Ingénierie","Architecture","Plateau"}', '{"1999 — Marché central de Pobè, modèle de ventilation naturelle reproduit dans six villes."}', '{"mathias","auguste","theophile"}', '', '{"Profil consulté":"1 120 fois","Capsules vues":"—","Téléchargements PDF":"31","Mentorés actifs":"2"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('gisele', 'Mme Gisèle Hountondji', 'Pionnière', 'Finance', 'Littoral', 'Banquière — Directrice générale honoraire d''une banque pan-UEMOA', 'Banquière. Trente-six ans dans la finance ouest-africaine, dont quinze à la tête d''un grand réseau.', 36, 'Honoraire', 'Mentorat ouvert', 1640, 60, 'https://images.unsplash.com/photo-1678225894316-b6e83cd06242?q=80&w=800&auto=format&fit=crop', '{"Finance","Banque","Littoral"}', '{"2011 — Lancement d''un produit de crédit aux coopératives féminines, 40 000 bénéficiaires."}', '{"emile","anastasie","henriette"}', '', '{"Profil consulté":"1 640 fois","Capsules vues":"—","Téléchargements PDF":"44","Mentorés actifs":"3"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('anastasie', 'Mme Anastasie Adékambi', 'Pionnière', 'Agriculture', 'Zou', 'Entrepreneure — Fondatrice d''une coopérative de 1 200 productrices', 'Entrepreneure rurale. De douze productrices en 1992 à mille deux cents aujourd''hui.', 33, 'Active', 'Conseil ponctuel', 1290, 45, 'https://images.unsplash.com/photo-1657356217673-4f7000f768b4?q=80&w=800&auto=format&fit=crop', '{"Agriculture","Entrepreneuriat","Zou"}', '{"2008 — Première unité de transformation gérée et détenue à 100 % par les productrices."}', '{"solange","gisele","auguste"}', '', '{"Profil consulté":"1 290 fois","Capsules vues":"—","Téléchargements PDF":"27","Mentorés actifs":"4"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('theophile', 'M. Théophile Aïzonou', 'Pionnier', 'Administration', 'Collines', 'Haut fonctionnaire — Ancien secrétaire général de préfecture', 'Administrateur civil. Trente-sept ans au service de l''État, de la sous-préfecture au cabinet ministériel.', 37, 'Retraité', 'Mentorat ouvert', 870, 40, null, '{"Administration","Service public","Collines"}', '{"2009 — Guichet unique départemental, délai d''acte ramené de 21 à 3 jours."}', '{"henriette","auguste","mathias"}', '', '{"Profil consulté":"870 fois","Capsules vues":"—","Téléchargements PDF":"12","Mentorés actifs":"1"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('albertine', 'Pr Albertine Gbaguidi', 'Pionnière', 'Recherche', 'Couffo', 'Linguiste — Documentation des langues fon et adja', 'Linguiste. Trente-quatre ans à documenter, transcrire et enseigner les langues nationales du Bénin.', 34, 'Professeure émérite', 'Mentorat ouvert', 980, 50, null, '{"Recherche","Linguistique","Couffo"}', '{"2013 — Premier dictionnaire fon-français-fon de référence, 28 000 entrées."}', '{"emile","solange","auguste"}', '', '{"Profil consulté":"980 fois","Capsules vues":"—","Téléchargements PDF":"35","Mentorés actifs":"2"}'::jsonb, true);
insert into public.pioneers (id, name, prefix, sector, region, headline, long_bio, experience, status, availability, views, completion, photo_url, tags, fiertes, related_ids, legacy, stats, published) values ('norbert', 'Dr Norbert Quenum', 'Pionnier', 'Santé', 'Donga', 'Chirurgien — Pionnier de la chirurgie de district au nord du Bénin', 'Chirurgien généraliste. Trente-deux ans à opérer là où il n''y avait personne pour le faire.', 32, 'Retraité actif', 'Conseil ponctuel', 1056, 55, 'https://plus.unsplash.com/premium_photo-1693146325979-027c2b00835c?q=80&w=800&auto=format&fit=crop', '{"Santé","Chirurgie","Donga"}', '{"2006 — Protocole de chirurgie d''urgence adapté aux blocs de district, diffusé dans le nord."}', '{"cecile","mathias","theophile"}', '', '{"Profil consulté":"1 056 fois","Capsules vues":"210","Téléchargements PDF":"19","Mentorés actifs":"3"}'::jsonb, true);
