insert into public.testimonials (pioneer_id, text, author, role, sort_order) values ('cecile', 'Cécile a formé toute une génération de médecins de l''Ouémé. Sa rigueur méthodologique et sa connaissance intime du terrain font partie du patrimoine professionnel béninois.', 'Dr Paul Dossou', 'Ancien directeur national de la santé', 0);
