insert into public.articles (id, author_pioneer_id, sector, kind, read_time, article_date, reads, title, excerpt, body, published) values ('resilience', 'cecile', 'Santé', 'Analyse sectorielle', '8 min', 'il y a 3 jours', '2 847', 'Ce que trente-huit ans en zone rurale m''ont appris sur la résilience des systèmes de soins', 'Quand j''ai pris mes fonctions au dispensaire de Kétou en 1988, nous étions deux pour couvrir trois sous-préfectures. La théorie disait qu''il fallait des moyens. La réalité enseignait autre chose.', '["Quand j''ai pris mes fonctions au dispensaire de Kétou en 1988, nous étions deux pour couvrir trois sous-préfectures. La théorie disait qu''il fallait des moyens. La réalité enseignait autre chose. Quarante ans plus tard, je voudrais partager ce que cette pratique m''a appris — pour celles et ceux qui poursuivront le travail.","La première leçon est que la résilience d''un système de soins ne se mesure pas à ses équipements, mais à la densité du tissu humain qui l''entoure. Le relais communautaire, la matrone, l''instituteur du village : voilà l''infrastructure réelle. Quand l''épidémie de méningite a frappé en 1996, ce ne sont pas les ambulances qui ont tenu — c''est ce réseau.","La deuxième leçon concerne la sobriété. Un protocole qui dépend d''une chaîne du froid parfaite ou d''un approvisionnement régulier n''est pas un protocole, c''est un vœu. Nous avons appris à concevoir des soins itinérants qui fonctionnaient même quand la route était coupée trois mois par an.","La troisième leçon, enfin : on ne planifie pas la santé publique depuis la capitale. On l''écoute depuis le village, et on remonte. C''est l''inverse de ce qu''on m''avait enseigné, et c''est la seule chose qui ait jamais marché."]'::jsonb, true);
insert into public.articles (id, author_pioneer_id, sector, kind, read_time, article_date, reads, title, excerpt, body, published) values ('eau-borgou', 'mathias', 'Ingénierie', 'Retour d''expérience', '5 min', 'il y a 6 jours', '984', 'Construire un réseau d''eau quand le budget vous manque : ce que j''ai appris au Borgou', 'L''ingéniosité naît de la contrainte. Trois projets emblématiques, trois leçons qu''aucune école d''ingénieurs n''enseigne.', '["L''ingéniosité naît de la contrainte. Je l''ai compris sur trois chantiers du Borgou, où le budget disponible ne couvrait jamais plus du tiers de ce qu''un bureau d''études classique aurait préconisé.","Le premier réflexe a été d''abandonner le pompage partout où la topographie le permettait. Un réseau gravitaire ne tombe pas en panne, ne consomme rien, et la commune peut l''entretenir seule. C''est moins élégant sur un plan — mais c''est encore en service trente ans après.","Le deuxième principe : impliquer les futurs usagers dès le tracé. Ils connaissent les points d''eau ancestraux, les zones inondables, les conflits fonciers. Aucune étude géotechnique ne remplace cette mémoire-là.","La dernière leçon est la plus difficile à transmettre : savoir dire non à un financement qui impose une technologie ingérable localement. Un beau château d''eau à l''abandon coûte plus cher, humainement, qu''une borne-fontaine modeste qui dure."]'::jsonb, true);
insert into public.articles (id, author_pioneer_id, sector, kind, read_time, article_date, reads, title, excerpt, body, published) values ('magistrature', 'henriette', 'Droit', 'Mémoire', '12 min', 'il y a 9 jours', '1 203', 'Vingt années à former la magistrature béninoise : ce qui reste à faire', 'L''indépendance de la justice ne tient pas qu''à ses textes. Elle se construit dans la qualité de la formation initiale.', '["L''indépendance de la justice ne tient pas qu''à ses textes. Elle se construit, jour après jour, dans la qualité de la formation initiale des magistrats — et c''est à cette tâche que j''ai consacré la seconde moitié de ma carrière.","Quand j''ai pris la refonte du module OHADA en 2010, le constat était simple : nous formions d''excellents récitants du droit et de médiocres praticiens du doute. Or un bon juge est d''abord quelqu''un qui sait suspendre son jugement.","Ce qui reste à faire est immense. La formation continue est encore le parent pauvre. Un magistrat nommé en 1995 n''a, dans bien des cas, jamais été réexposé à une salle de cours. C''est une anomalie que la relève devra corriger.","Je crois aussi que nous devons documenter notre propre jurisprudence. Tant que la nôtre n''est pas accessible, commentée, enseignée, nous resterons les commentateurs du droit des autres."]'::jsonb, true);
insert into public.articles (id, author_pioneer_id, sector, kind, read_time, article_date, reads, title, excerpt, body, published) values ('mais-sahelien', 'solange', 'Agriculture', 'Pédagogie', '6 min', 'il y a 12 jours', '661', 'Le maïs sahélien : les sept variétés que personne n''a documentées', 'Trente-cinq ans de sélection variétale m''ont permis d''identifier sept lignées résistantes à la sécheresse, jamais inscrites dans aucun registre officiel.', '["Trente-cinq ans de sélection variétale m''ont permis d''identifier sept lignées de maïs résistantes à la sécheresse, jamais inscrites dans aucun registre officiel. Elles existent pourtant, dans les champs, depuis des générations.","La lignée que nous appelons « Sô-3 » tolère jusqu''à quarante-cinq jours de stress hydrique. Aucun catalogue commercial ne la connaît. Si les paysans qui la conservent disparaissent sans transmettre, elle disparaît avec eux.","Documenter une variété paysanne, ce n''est pas seulement noter un rendement. C''est consigner le geste de conservation, le calendrier, les associations culturales, les récits qui l''accompagnent.","Mon travail aujourd''hui consiste à former des paysans-sélectionneurs. Soixante à ce jour. Chacun devient le gardien d''une bibliothèque vivante — et c''est, je crois, la forme la plus concrète de transmission."]'::jsonb, true);
insert into public.articles (id, author_pioneer_id, sector, kind, read_time, article_date, reads, title, excerpt, body, published) values ('bceao', 'emile', 'Recherche', 'Analyse sectorielle', '11 min', 'il y a 16 jours', '1 047', 'Quarante ans à observer la BCEAO : pourquoi nos modèles d''inflation se trompent', 'Trois épisodes d''inflation que les modèles classiques n''ont pas vu venir, et ce qu''ils nous enseignent sur la souveraineté monétaire.', '["Trois épisodes d''inflation, en quarante ans d''observation de la zone, n''ont pas été anticipés par les modèles classiques. Ce n''est pas un détail technique : c''est le signe que nous appliquons des cadres pensés pour d''autres économies.","Le premier biais est de traiter le secteur informel comme un résidu. Or il est le canal principal de transmission des prix. Un modèle qui l''ignore ne décrit pas notre réalité.","Le second est temporel. Nos économies réagissent aux chocs avec des délais que les modèles importés sous-estiment systématiquement. La saisonnalité agricole, à elle seule, déforme toute lecture trimestrielle.","Je ne plaide pas contre la modélisation — j''y ai consacré ma vie. Je plaide pour qu''on observe d''abord, longuement, avant de modéliser. Le marché de Dantokpa enseigne plus, certains jours, qu''un séminaire."]'::jsonb, true);
insert into public.articles (id, author_pioneer_id, sector, kind, read_time, article_date, reads, title, excerpt, body, published) values ('enseignement-technique', 'auguste', 'Éducation', 'Témoignage', '7 min', 'il y a 21 jours', '538', 'Pourquoi j''ai consacré ma vie à l''enseignement technique', 'On a trop longtemps fait croire aux enfants que la main qui travaille valait moins que la main qui écrit.', '["On a trop longtemps fait croire aux enfants — et à leurs parents — que la main qui travaille valait moins que la main qui écrit. J''ai passé trente-neuf ans à démontrer le contraire.","Le premier lycée technique que j''ai dirigé, à Lokossa, était considéré comme le lycée des élèves « qui n''avaient pas réussi ». En dix ans, il est devenu celui qu''on choisissait.","Le secret n''est pas pédagogique, il est culturel. Tant qu''un bon soudeur n''est pas socialement respecté autant qu''un bon juriste, aucune réforme des programmes ne tiendra.","Je laisse quatre établissements et plus de trois mille diplômés. Mais je laisse surtout, je l''espère, une conviction : former à un métier, c''est transmettre une dignité."]'::jsonb, true);
insert into public.articles (id, author_pioneer_id, sector, kind, read_time, article_date, reads, title, excerpt, body, published) values ('cooperative', 'anastasie', 'Agriculture', 'Pédagogie', '7 min', 'il y a 25 jours', '472', 'Fonder une coopérative féminine quand on m''avait dit que c''était impossible', 'De 12 productrices en 1992 à 1 200 aujourd''hui. Ce que nous avons fait, ce que nous referions.', '["De douze productrices en 1992 à mille deux cents aujourd''hui. Quand j''ai commencé, on m''a expliqué — avec bienveillance — que ce n''était pas possible. Pas de garanties, pas de foncier, pas de marché.","Nous avons commencé par le plus petit dénominateur commun : transformer le soja ensemble, une journée par semaine. Pas de statuts, pas de banque. Juste un rythme.","La bascule est venue en 2008, avec notre première unité de transformation détenue à 100 % par les productrices. C''est la propriété qui change tout : elle transforme une bénéficiaire en décideuse.","Ce que je transmets aux jeunes femmes qui veulent entreprendre : ne cherchez pas l''investisseur d''abord. Cherchez le rythme, la confiance, la première vente. Le reste suit."]'::jsonb, true);
